def format_output_state(reg3: int) -> str:
    """Format OUTPUT_ENABLE_CTRL register state to readable string."""
    enabled = []
    for i in range(3):
        if not (reg3 & (1 << i)):
            enabled.append(f'CLK{i}')
    if not enabled:
        return 'All outputs DISABLED'
    return ', '.join(enabled) + ' enabled'


